package be.schaubroeck.lpb.rkm.rekenmotor.mapkeys;

import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LogTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import lombok.Data;
import lombok.RequiredArgsConstructor;
import org.apache.commons.lang.builder.EqualsBuilder;
import org.apache.commons.lang.builder.HashCodeBuilder;
import org.joda.time.LocalDate;

@Data
@RequiredArgsConstructor
public class ManueleTussenkomstKey {

    private final Opdracht opdracht;
    private final AardKodeExtensie aardKodeExtensie;
    private final LocalDate beginDatum;
    private final LocalDate eindDatum;
    private final MoneyKey bedragType;
    private final LnedefRegBv regime;

    public ManueleTussenkomstKey(RekenHoofd hoofd, RekenLijn lijn, RekenBedrag bedrag) {
        this(hoofd.getOpdracht(), lijn.getAardKodeExtensie(), lijn.getBeginDatum(), lijn.getEindDatum(),
                RekenTools.bedragTypeToMoneyKey(bedrag.getBedragType(), lijn.getRegimeBv(), hoofd.getBeginDatum()), lijn.getRegimeBv());
    }

    public ManueleTussenkomstKey(ManueleTussenkomstKey key, LocalDateInterval periode) {
        this(key.getOpdracht(), key.getAardKodeExtensie(), periode.getStart(), periode.getEnd(), key.getBedragType(), key.getRegime());
    }

    public LocalDate getDatum() {
        return beginDatum;
    }

    public LocalDateInterval getPeriode() {
        return new LocalDateInterval(beginDatum, eindDatum);
    }

    @Override
    public boolean equals(final Object object) {
        if (!(object instanceof ManueleTussenkomstKey)) {
            return false;
        }
        ManueleTussenkomstKey rhs = (ManueleTussenkomstKey) object;
        return new EqualsBuilder().append(this.opdracht.getId(), rhs.opdracht.getId())
                .append(this.aardKodeExtensie.getId(), rhs.aardKodeExtensie.getId()).append(this.beginDatum, rhs.beginDatum)
                .append(this.eindDatum, rhs.eindDatum).append(this.bedragType, rhs.bedragType).append(this.regime, rhs.regime).isEquals();
    }

    private static final int HASH_CST1 = 845567;
    private static final int HASH_CST2 = 48527;

    @Override
    public int hashCode() {
        return new HashCodeBuilder(HASH_CST1, HASH_CST2).append(opdracht.getId()).append(aardKodeExtensie.getId()).append(beginDatum)
                .append(eindDatum).append(bedragType).append(regime).toHashCode();
    }

    @Override
    public String toString() {
        return getClass().getSimpleName() + "[" + LogTools.toSimpleLog(opdracht) + ", " + ", " + aardKodeExtensie.getAard() + "-" + aardKodeExtensie
                .getCode() + "-" + aardKodeExtensie.getExtensie() + ", " + bedragType + ", " + regime + "]";
    }

}
